INSERT INTO `qx_meeting` VALUES (1782290735566,'000000','1',NULL,NULL,NULL,NULL,'<p><br></p>','[{\"name\": \"11\"}]','[{\"time\": \"Tue, 23 Jun 2026 23:07:00 GMT - Wed, 24 Jun 2026 06:07:00 GMT\", \"title\": \"11\"}]',0,1,'2026-06-24 08:45:35','2026-06-24 08:45:56'),(1782290998854,'000000','第二届气象经济博览会新闻发布会','合肥滨湖国际会展中心 · 综合会议厅','2026-06-24 16:00:00','聚焦气象科技赋能经济发展新机遇','https://images.unsplash.com/photo-1511578314322-379afb476865?q=80&w=1600&auto=format&fit=crop','<p>&lt;h2&gt;第二届气象经济博览会新闻发布会圆满召开&lt;/h2&gt;<br> &lt;p&gt;近日，第二届气象经济博览会新闻发布会在合肥滨湖国际会展中心圆满召开。本次发布会围绕&lt;strong&gt;气象科技、产业融合、数字经济、绿色发展&lt;/strong&gt;等核心方向，全面介绍了本届博览会的筹备进展、展区规划、会议活动及重点亮点。&lt;/p&gt;<br><br> &lt;p&gt;发布会现场，主办方介绍，本届博览会将以“气象赋能经济，科技引领未来”为主题，重点展示气象服务在农业生产、交通运输、能源管理、城市治理、金融保险、生态保护等领域的创新应用成果。&lt;/p&gt;<br><br> &lt;blockquote&gt;<br> 本届博览会将进一步推动气象科技成果转化，促进气象服务与实体经济深度融合。<br> &lt;/blockquote&gt;<br><br> &lt;h3&gt;大会亮点&lt;/h3&gt;<br> &lt;ul&gt;<br> &lt;li&gt;汇聚气象、经济、科技、产业等多领域专家学者；&lt;/li&gt;<br> &lt;li&gt;集中展示气象装备、数据服务、智慧预警、行业解决方案；&lt;/li&gt;<br> &lt;li&gt;设置专题论坛、成果发布、项目对接、展商推介等活动；&lt;/li&gt;<br> &lt;li&gt;推动气象服务在城市运行、产业发展和民生保障中的应用。&lt;/li&gt;<br> &lt;/ul&gt;<br><br> &lt;h3&gt;展会规模&lt;/h3&gt;<br> &lt;p&gt;本届博览会预计展览面积超过 &lt;strong&gt;40,000 平方米&lt;/strong&gt;，吸引 &lt;strong&gt;300+ 家参展企业&lt;/strong&gt;、&lt;strong&gt;50+ 场专题会议&lt;/strong&gt;及 &lt;strong&gt;10,000+ 名专业观众&lt;/strong&gt;参与。&lt;/p&gt;<br><br> &lt;p&gt;现场还公布了大会总体日程、嘉宾阵容、展区设置及参展服务安排。多家媒体记者围绕气象经济发展趋势、产业合作机会、展会筹备情况等内容进行了提问。&lt;/p&gt;<br><br> &lt;p&gt;随着新闻发布会的圆满召开，第二届气象经济博览会正式进入全面推进阶段。大会将持续搭建气象科技成果展示、产业资源对接、行业交流合作的重要平台，为气象经济高质量发展注入新动能。&lt;/p&gt;</p>','[{\"name\": \"王明\", \"title\": \"中国气象服务协会副会长\", \"avatar\": \"https://images.unsplash.com/photo-1560250097-0b93528c311a?q=80&w=400&auto=format&fit=crop\"}, {\"name\": \"李建华\", \"title\": \"国家气象中心专家委员会委员\", \"avatar\": \"https://images.unsplash.com/photo-1556157382-97eda2d62296?q=80&w=400&auto=format&fit=crop\"}, {\"name\": \"周雨晴\", \"title\": \"气象经济产业研究院研究员\", \"avatar\": \"https://images.unsplash.com/photo-1573496359142-b8d87734a5a2?q=80&w=400&auto=format&fit=crop\"}]','[{\"time\": \"16:00-16:10\", \"title\": \"参会媒体及嘉宾入场签到，领取会议资料\"}, {\"time\": \"16:10-16:30\", \"title\": \"介绍发布会背景、出席嘉宾及整体流程\"}, {\"time\": \"16:30-16:50\", \"title\": \"介绍第二届气象经济博览会主题、规模、展区规划及重点活动\"}, {\"time\": \"16:50-17:30\", \"title\": \"领导嘉宾、参会代表及媒体进行集体合影。\"}]',0,0,'2026-06-24 08:49:59','2026-06-24 08:59:07'),(1782291161297,'000000','测试','测试','2026-06-25 00:00:00','测试',NULL,'<p><br></p>','[{\"name\": \"王明\"}]','[{\"time\": \"07:00-09:00\", \"title\": \"测试\"}]',1,0,'2026-06-24 08:52:41','2026-06-24 08:55:21'),(1782291183585,'000000','测试2','测试2','2026-06-26 00:00:00',NULL,NULL,'<p><br></p>','[{\"name\": \"测试\"}]','[{\"time\": \"00:00-07:00\", \"title\": \"测试\"}]',1,0,'2026-06-24 08:53:03','2026-06-24 08:55:16');
/*!40000 ALTER TABLE `qx_meeting` ENABLE KEYS */;
UNLOCK TABLES;

