INSERT INTO `qx_news_article` VALUES (1782282114114,'000000','第二届气象经济博览会新闻发布会圆满召开','聚焦气象科技创新，助力气象经济高质量发展','https://picsum.photos/800/450?random=101','2026-06-24 00:00:00','<p><strong>5月16日，</strong><u><strong>第二届气象经济博览会新闻发布会在合肥举行</strong></u><strong>。会议围绕展会主题、展区规划、参展服务、同期活动等内容进行了重点介绍。本届博览会将汇聚气象科技、智慧城市、应急管理、低空经济、</strong><span style=\"background-color: rgb(231, 95, 51);\"><strong>农业气象等多个领域的企业与机构</strong></span><strong>，</strong><span style=\"color: rgb(0, 0, 0); font-family: 仿宋;\"><strong>集中展示气象经济发展的最新成果</strong></span><strong>。</strong><img src=\"https://s3.minion.xlcig.cn/public-assets/news/1782286035615_icon-512x512.png\" alt=\"icon-512x512.png\" data-href=\"https://s3.minion.xlcig.cn/public-assets/news/1782286035615_icon-512x512.png\" style=\"\"/></p>','2026-06-24 06:21:54','2026-06-24 07:46:20',0),(1782282141043,'000000','中国气象服务协会关于举办第二届气象经济博览会的通知','展会将于2025年7月18日至20日在合肥滨湖国际会展中心举办','https://picsum.photos/800/450?random=103','2026-06-23 00:00:00','为推动气象服务产业发展，促进气象科技成果转化，中国气象服务协会拟举办第二届气象经济博览会。本届展会将设置气象装备、智慧气象、气象服务、气象数据应用、应急减灾等专题展区，并同期举办多场论坛、供需对接会和成果发布活动。','2026-06-24 06:22:21','2026-06-24 07:46:21',0),(1782282162435,'000000','展商报名通道正式开启，早鸟优惠限时进行中','优质展位开放申请，欢迎相关单位报名参展','https://picsum.photos/800/450?random=102','2026-06-23 00:00:00','第二届气象经济博览会展商报名通道现已正式开启。参展企业可通过官网提交展位申请，主办方将根据展品类别、展示需求和展区规划进行统一安排。早鸟报名期间，符合条件的参展单位可享受展位服务优惠及官方宣传资源支持。','2026-06-24 06:22:42','2026-06-24 07:46:22',0),(1782282184125,'000000','大会同期论坛议程陆续公布','聚焦气象服务、智慧城市、低空经济与应急减灾','https://picsum.photos/800/450?random=104',NULL,'本届博览会期间将举办多场专题论坛，内容涵盖气象服务创新、人工智能气象应用、气象数据价值转化、极端天气风险防控、低空经济气象保障等方向。论坛将邀请行业专家、科研机构代表及企业负责人共同探讨气象经济发展新机遇','2026-06-24 06:23:04','2026-06-24 07:46:23',0);
/*!40000 ALTER TABLE `qx_news_article` ENABLE KEYS */;
UNLOCK TABLES;

