INSERT INTO `qx_special_guest` VALUES (1782350801219,'000000','李明远','中国气象服务协会副会长',3,'https://images.unsplash.com/photo-1560250097-0b93528c311a?w=400&h=400&fit=crop&crop=face','长期从事气象经济、气象服务产业化与智慧气象应用研究，参与多项行业标准制定与产业规划工作',1,0,'2026-06-25 01:26:42','2026-06-25 03:05:01'),(1782350825750,'000000','张慧','国家气象中心高级工程师',2,'https://images.unsplash.com/photo-1494790108377-be9c29b29330?w=400&h=400&fit=crop&crop=face','专注于气象大数据分析、灾害预警模型与城市气象服务体系建设，拥有丰富的项目实践经验',1,0,'2026-06-25 01:27:07','2026-06-25 01:27:07'),(1782350846206,'000000','王建国','智慧城市研究院院长',1,'https://images.unsplash.com/photo-1519085360753-af0119f7cbe7?w=400&h=400&fit=crop&crop=face','主要研究智慧城市、数字孪生与公共安全应急管理，推动气象数据与城市治理场景深度融合。',1,0,'2026-06-25 01:27:27','2026-06-25 01:27:27'),(1782350873688,'000000','陈思雨','气象经济研究中心主任',4,'https://images.unsplash.com/photo-1580489944761-15a19d654956?w=400&h=400&fit=crop&crop=face','围绕气象经济价值评估、气象产业服务模式创新及企业气象风险管理开展长期研究',1,0,'2026-06-25 01:27:55','2026-06-25 01:27:55'),(1782350904199,'000000','赵伟','云计算与数据平台专家',5,'https://images.unsplash.com/photo-1500648767791-00dcc994a43e?w=400&h=400&fit=crop&crop=face','负责多个大型数据平台建设项目，擅长云计算架构、数据治理、可视化分析与业务系统集成',1,0,'2026-06-25 01:28:25','2026-06-25 01:28:25'),(1782350925303,'000000','刘雅婷','生态环境气象服务专家',6,'https://images.unsplash.com/photo-1534528741775-53994a69daeb?w=400&h=400&fit=crop&crop=face','聚焦生态环境监测、双碳气象服务与区域气候风险评估，参与多个生态气象服务平台建设。',1,0,'2026-06-25 01:28:46','2026-06-25 01:28:46'),(1782350968655,'000000','周启航','中国气象局公共气象服务中心专家',7,'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=400&h=400&fit=crop&crop=face','长期关注公共气象服务能力建设，参与气象服务产品创新、城市精细化预报和行业应用推广工作。',1,0,'2026-06-25 01:29:30','2026-06-25 01:29:30'),(1782351256154,'000000','孙若琳','气象产业创新联盟秘书长',8,'https://images.unsplash.com/photo-1531123897727-8f129e1688ce?w=400&h=400&fit=crop&crop=face','负责气象产业资源整合、企业合作对接与产业生态建设，推动气象服务与多行业场景融合发展',1,0,'2026-06-25 01:34:17','2026-06-25 01:34:17'),(1782351279778,'000000','何志强','应急管理与气象防灾专家',9,'https://images.unsplash.com/photo-1506794778202-cad84cf45f1d?w=400&h=400&fit=crop&crop=face','深耕灾害风险防控、应急指挥调度和气象预警联动机制建设，具备丰富的一线项目经验。',1,0,'2026-06-25 01:34:41','2026-06-25 01:34:41');
